import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import './ForumHome.css';
import TopicSidebar from '../components/TopicSidebar';
import NewThreadModal from '../components/NewThreadModal';

function ForumHome() {
  const [discussions, setDiscussions] = useState([]);
  const [isModalOpen, setIsModalOpen] = useState(false);

  useEffect(() => {
    axios.get('http://localhost:5000/api/discussions')
      .then(response => setDiscussions(response.data))
      .catch(error => console.error('Error fetching discussions:', error));
  }, []);

  const handlePostDiscussion = (newPost) => {
    axios.post('http://localhost:5000/api/discussion', newPost)
      .then(() => setDiscussions([newPost, ...discussions]))
      .catch(error => console.error('Error posting discussion:', error));
  };

  return (
    <div className="forum-home">
      <TopicSidebar />
      <NewThreadModal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} onPost={handlePostDiscussion} />
      <button onClick={() => setIsModalOpen(true)}>Start a discussion</button>
      {discussions.map(d => (
        <div key={d.id}>
          <Link to={`/thread/${d.id}`}>{d.title}</Link>
          <span>{d.topic}</span>
        </div>
      ))}
    </div>
  );
}

export default ForumHome;
